using Microsoft.Win32;using System;using System.Collections.Generic;using System.IO;using System.Linq;using System.Windows;using System.Windows.Controls;using System.Windows.Media.Imaging;using КулинарнаяКнига.ApplicationData;using КулинарнаяКнига.AppData;
namespace КулинарнаяКнига.Pages{public partial class AddEditRecipePage:Page{private Recipes _r;private List<RecipeImages> _images=new List<RecipeImages>();private int _currentIndex=0;public AddEditRecipePage(Recipes r){InitializeComponent();_r=r??new Recipes();DataContext=_r;cmbCategory.ItemsSource=AppConnect.model01.Categories.ToList();cmbAuthor.ItemsSource=AppConnect.model01.Authors.ToList();if(r!=null){cmbCategory.SelectedItem=AppConnect.model01.Categories.FirstOrDefault(x=>x.CategoryID==r.CategoryID);cmbAuthor.SelectedItem=AppConnect.model01.Authors.FirstOrDefault(x=>x.AuthorID==r.AuthorID);_images=AppConnect.model01.RecipeImages.Where(x=>x.RecipeID==r.RecipeID).ToList();}LoadImage();}
void LoadImage(){if(_images.Count==0)return;try{var p=Path.Combine(AppDomain.CurrentDomain.BaseDirectory,"..\\..\\..",_images[_currentIndex].ImagePath);if(File.Exists(p)){var b=new BitmapImage();b.BeginInit();b.CacheOption=BitmapCacheOption.OnLoad;b.UriSource=new Uri(p,UriKind.Absolute);b.EndInit();b.Freeze();PhotoImage.Source=b;recipeNamePhoto.Text=Path.GetFileName(p);}}catch(Exception ex){MessageBox.Show(ex.Message);}}
void Prev_Click(object s,RoutedEventArgs e){if(_images.Count==0)return;_currentIndex=(_currentIndex-1+_images.Count)%_images.Count;LoadImage();}void Next_Click(object s,RoutedEventArgs e){if(_images.Count==0)return;_currentIndex=(_currentIndex+1)%_images.Count;LoadImage();}
void Upload_Click(object s,RoutedEventArgs e){var d=new OpenFileDialog();if(d.ShowDialog()!=true)return;var imgDir=Path.Combine(AppDomain.CurrentDomain.BaseDirectory,"..\\..\\..","Images");Directory.CreateDirectory(imgDir);var file=Path.GetFileName(d.FileName);var dest=Path.Combine(imgDir,file);File.Copy(d.FileName,dest,true);_images.Add(new RecipeImages{RecipeID=_r.RecipeID,ImagePath=$"Images\\{file}"});LoadImage();}
void Save_Click(object s,RoutedEventArgs e){if(string.IsNullOrWhiteSpace(_r.RecipeName)){MessageBox.Show("Название обязательно");return;}var c=cmbCategory.SelectedItem as Categories;var a=cmbAuthor.SelectedItem as Authors;if(c!=null)_r.CategoryID=c.CategoryID;if(a!=null)_r.AuthorID=a.AuthorID;try{if(_r.RecipeID==0)AppConnect.model01.Recipes.Add(_r);AppConnect.model01.SaveChanges();foreach(var i in _images.Where(x=>x.ImageID==0)){i.RecipeID=_r.RecipeID;AppConnect.model01.RecipeImages.Add(i);}AppConnect.model01.SaveChanges();NavigationService?.Navigate(new RecipesPage());}catch(Exception ex){MessageBox.Show(ex.Message);}}
void Steps_Click(object s,RoutedEventArgs e){NavigationService?.Navigate(new CookingStepsPage(_r));}}
}
